type Cell = string;

const keyOf = (x: number, y: number): Cell => `${x},${y}`;

const parseCell = (cell: Cell): [number, number] => {
  const [x, y] = cell.split(",").map(Number);
  return [x, y];
};

const neighborsOf = (cell: Cell): Cell[] => {
  const [x, y] = parseCell(cell);
  const neighbors: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      neighbors.push(keyOf(x + dx, y + dy));
    }
  }
  return neighbors;
};

const countLiveNeighbors = (cell: Cell, livingCells: Set<Cell>): number =>
  neighborsOf(cell).filter((neighbor) => livingCells.has(neighbor)).length;

const candidateCells = (livingCells: Set<Cell>): Set<Cell> => {
  const candidates = new Set<Cell>();
  for (const cell of livingCells) {
    candidates.add(cell);
    for (const neighbor of neighborsOf(cell)) candidates.add(neighbor);
  }
  return candidates;
};

const survives = (cell: Cell, livingCells: Set<Cell>): boolean => {
  const liveNeighbors = countLiveNeighbors(cell, livingCells);
  const isAlive = livingCells.has(cell);
  if (isAlive) return liveNeighbors === 2 || liveNeighbors === 3;
  return liveNeighbors === 3;
};

export function nextGeneration(livingCells: Set<Cell>): Set<Cell> {
  const next = new Set<Cell>();
  for (const cell of candidateCells(livingCells)) {
    if (survives(cell, livingCells)) next.add(cell);
  }
  return next;
}
